index 9df08553d86e..18ec8c9cd4a4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8789,6 +8789,78 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       }
     }
   }
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    // fcmp pred (fptrunc X), (fptrunc Y) -> fcmp X, Y
+    if (match(Op1, m_FPTrunc(m_Value(Y))) && X->getType() == Y->getType())
+      return new FCmpInst(Pred, X, Y, "", &I);
+
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      // For fcmp pred (fptrunc X), C, we need to find a threshold value D
+      // in X's type such that the comparison is equivalent.
+      // With round-to-nearest-ties-to-even:
+      // - For oge/uge/olt/ult: threshold is the midpoint between C and the previous float
+      // - For ogt/ugt/ole/ule: threshold is the midpoint between C and the next float
+      const fltSemantics &TruncSem =
+          I.getOperand(0)->getType()->getScalarType()->getFltSemantics();
+      const fltSemantics &SrcSem =
+          X->getType()->getScalarType()->getFltSemantics();
+
+      // Only handle conversion to smaller type (e.g., double -> float)
+      if (APFloat::semanticsPrecision(SrcSem) <=
+          APFloat::semanticsPrecision(TruncSem))
+        goto fptrunc_end;
+
+      // Compute half ULP in the truncated type (as a value in source type)
+      // half_ulp = 2^(ilogb(C) - mantissa_bits_of_truncated_type - 1)
+      int Exp = ilogb(*C);
+      if (Exp == APFloat::IEK_Zero || Exp == APFloat::IEK_Inf ||
+          Exp == APFloat::IEK_NaN)
+        goto fptrunc_end;
+
+      // Number of mantissa bits in the truncated type (excluding implicit bit)
+      int MantissaBits = APFloat::semanticsPrecision(TruncSem) - 1;
+      APFloat HalfULP = scalbn(APFloat::getOne(SrcSem), Exp - MantissaBits - 1,
+                               APFloat::rmNearestTiesToEven);
+
+      // Convert C to source semantics for threshold computation
+      bool Lossy;
+      APFloat Threshold = *C;
+      Threshold.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+
+      // Compute threshold based on predicate
+      switch (Pred) {
+      default:
+        goto fptrunc_end;
+      case FCmpInst::FCMP_OGE:
+      case FCmpInst::FCMP_UGE:
+      case FCmpInst::FCMP_OLT:
+      case FCmpInst::FCMP_ULT:
+        // threshold = C - half_ulp
+        Threshold.subtract(HalfULP, APFloat::rmNearestTiesToEven);
+        break;
+      case FCmpInst::FCMP_OGT:
+      case FCmpInst::FCMP_UGT:
+      case FCmpInst::FCMP_OLE:
+      case FCmpInst::FCMP_ULE:
+        // threshold = C + half_ulp
+        Threshold.add(HalfULP, APFloat::rmNearestTiesToEven);
+        break;
+      }
+
+      // Avoid denormals and ensure we have a valid threshold
+      APFloat ThresholdAbs = Threshold;
+      ThresholdAbs.clearSign();
+      if (Threshold.isNaN() || Threshold.isInfinity() ||
+          (ThresholdAbs.isNonZero() &&
+           ThresholdAbs < APFloat::getSmallestNormalized(SrcSem)))
+        goto fptrunc_end;
+
+      Constant *NewC = ConstantFP::get(X->getType(), Threshold);
+      return new FCmpInst(Pred, X, NewC, "", &I);
+    }
+  }
+fptrunc_end:;

   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.

